item.json.extracted_text ||
"";

if (!text) continue;


// ============================================
// STEP 1 — CLEAN OCR
// ============================================

text = text
.replace(/\r/g,"\n")
.replace(/---+/g,"\n")
.replace(/\n{2,}/g,"\n")
.replace(/\s{2,}/g," ")
.replace(/&\s*x3C;/gi,"<")
.replace(/Manufacturer reserves.*?notice\./gi,"")
.trim();


// ============================================
// STEP 2 — RESTORE HEADERS
// ============================================

const headers = [

"INTRODUCTION",
"GENERAL CHARACTERISTICS",

"ENGINE SPECIFICATIONS",

"ALTERNATOR CHARACTERISTICS",

"CONTROL PANEL",
"CONTROL MODULE",
"STANDARD SPECIFICATIONS",

"PROTECTION CIRCUITS",
"PRE-ALARMS",
"STOP ALARMS",

"OPTIONAL EQUIPMENTS",

"AKSA CERTIFICATES",
"CERTIFICATES",

"ISO 14001",
"TS ISO 8528",
"TS ISO 9001"

];

for (const h of headers){

const rx = new RegExp(h,"gi");

text=text.replace(
rx,
`\n###${h}###\n`
);

}


// ============================================
// STEP 3 — SECTION BOUNDARIES
// ============================================

function extractSection(start,end){

const s=text.search(
new RegExp(start,"i")
);

if(s<0) return "";

let e=text.length;

if(end){

const rem=text.substring(s);

const m=rem.search(
new RegExp(end,"i")
);

if(m>0) e=s+m;

}

return text.substring(
s,
e
).trim();

}


// ============================================
// STEP 4 — EXTRACT
// ============================================

let GENERAL=
extractSection(
"INTRODUCTION",
"ENGINE SPECIFICATIONS"
);

let ENGINE=
extractSection(
"ENGINE SPECIFICATIONS",
"ALTERNATOR CHARACTERISTICS"
);

let ALTERNATOR=
extractSection(
"ALTERNATOR CHARACTERISTICS",
"CONTROL PANEL"
);

let CONTROL=
extractSection(
"CONTROL PANEL",
"PROTECTION CIRCUITS"
);

let PROTECTION=
extractSection(
"PROTECTION CIRCUITS",
"OPTIONAL EQUIPMENTS"
);

let OPTIONS=
extractSection(
"OPTIONAL EQUIPMENTS",
"(ISO 14001|AKSA CERTIFICATES|CERTIFICATES)"
);

let CERT=
extractSection(
"(ISO 14001|AKSA CERTIFICATES|CERTIFICATES)",
null
);


// ============================================
// STEP 5 — DEDUP
// ============================================

function cleanBlock(v){

if(!v)
return "";

const lines=
v.split("\n")
.map(x=>x.trim())
.filter(Boolean);

return [
...new Set(lines)
].join("\n");

}

GENERAL=cleanBlock(GENERAL);
ENGINE=cleanBlock(ENGINE);
ALTERNATOR=cleanBlock(ALTERNATOR);
CONTROL=cleanBlock(CONTROL);
PROTECTION=cleanBlock(PROTECTION);
OPTIONS=cleanBlock(OPTIONS);
CERT=cleanBlock(CERT);


// ============================================
// STEP 6 — PLACEHOLDER PROTECTION
// ============================================

if(!GENERAL)
GENERAL="GENERAL DATA NOT FOUND";

if(!ENGINE)
ENGINE="ENGINE DATA NOT FOUND";

if(!ALTERNATOR)
ALTERNATOR="ALTERNATOR DATA NOT FOUND";

if(!CONTROL)
CONTROL="CONTROL PANEL DATA NOT FOUND";

if(!PROTECTION)
PROTECTION="PROTECTION DATA NOT FOUND";

if(!OPTIONS)
OPTIONS="OPTIONS DATA NOT FOUND";

if(!CERT)
CERT="CERTIFICATES DATA NOT FOUND";


// ============================================
// STEP 7 — BUILD CHUNKS
// ============================================

const sections=[

["GENERAL",GENERAL],
["ENGINE",ENGINE],
["ALTERNATOR",ALTERNATOR],
["CONTROL_PANEL",CONTROL],
["PROTECTION",PROTECTION],
["OPTIONS",OPTIONS],
