const results = [];

const LIMITS = {
  GENERAL: 1800,
  ENGINE: 2500,
  ALTERNATOR: 1000,
  CONTROL_PANEL: 1800,
  PROTECTION: 1400,
  OPTIONS: 1400,
  CERTIFICATES: 250
};

function splitText(text, maxLen) {
if (!text) return [];
text = text
.replace(/\r/g, "\n")
.replace(/\n{2,}/g, "\n")
.trim();
let parts = text.split(/###|\n/);
let chunks = [];
let current = "";
for (const partRaw of parts) {
const part = partRaw.trim();
if (!part) continue;
if (current.length + part.length < maxLen) {
current += "\n" + part;
} else {
if (current.trim()) {
chunks.push(current.trim());
}
current = part;
}
}
if (current.trim()) {
chunks.push(current.trim());
}
return chunks;
}

for (const item of items) {
const data = item.json;
const section = data.section || "GENERAL";
const limit = LIMITS[section] || 1500;
const text = data.content || "";
const subchunks = splitText(text, limit);
if (subchunks.length <= 1) {
const enrichedContent = `
Manufacturer: ${data.metadata?.manufacturer || ""}
Genset Model: ${data.metadata?.genset_model || ""}
Engine Model: ${data.metadata?.engine_model || ""}
Alternator Model: ${data.metadata?.alternator_model || ""}
Section: ${section}

${text}
`.trim();
results.push({
json: {
...data,
content: enrichedContent,
parent_chunk: data.chunk_id,
subchunk: 1
}
});
continue;
}
