const headerPatterns = [

{
pattern: /DESCRIPTION/gi,
replace: "\n###DESCRIPTION###\n"
},

{
pattern: /FEATURES/gi,
replace: "\n###FEATURES###\n"
},

{
pattern: /(1500\s*RPM.*?50\s*HZ\s*RATINGS|50\s*HZ\s*RATINGS|1500\s*RPM)/gi,
replace: "\n###1500_RPM_RATINGS###\n"
},

{
pattern: /GENERAL\s*ENGINE\s*DATA/gi,
replace: "\n###GENERAL_ENGINE_DATA###\n"
},

{
pattern: /RATINGS\s*DEFINITIONS/gi,
replace: "\n###RATINGS_DEFINITIONS###\n"
},

{
pattern: /COOLPAC\s*PERFORMANCE\s*DATA/gi,
replace: "\n###COOLPAC_PERFORMANCE_DATA###\n"
},

{
pattern: /WEIGHT\s*AND\s*DIMENSIONS/gi,
replace: "\n###WEIGHT_AND_DIMENSIONS###\n"
},

{
pattern: /FUEL\s*CONSUMPTION/gi,
replace: "\n###FUEL_CONSUMPTION###\n"
}

];

for (const h of headerPatterns) {
text = text.replace(
h.pattern,
h.replace
);
}


// =====================================
// SECTION EXTRACTOR
// =====================================

function extractSection(start,end){

const s = text.search(
new RegExp(start,"i")
);

if (s < 0) return "";

let e = text.length;

if (end){

const rem = text.substring(s);

const m = rem.search(
new RegExp(end,"i")
);

if (m > 0)
e = s + m;

}

return text.substring(s,e).trim();

}


